---@param replaceStatus number 替换类型，0：默认，1：不替换，2：强制替换（暂时服务微小，登录页需求）
function LDisplaySpine:CreateSpine(parentTrans,spineName,spineType,wndCls,replaceStatus)
	self._wndCls = wndCls
	self._constSpineName = spineName

	replaceStatus = replaceStatus or 0
	if replaceStatus == 0 then
		spineName = gLGameLanguage:GetPrefabName(spineName)
	elseif replaceStatus == 2 then
		spineName = gLGameLanguage:GetForcePrefabName(spineName)
	end

	self._isAniSensitive = gLGameLanguage:IsAniSensitive(spineName)

	spineType = spineType or 0
	self._spineType = spineType
	self._orgSpineName = spineName
	self._spineName = spineName

	local defaultSpineName = nil
	local defaultSpinePath = nil

	local spinePath = "Spine/"..spineName
	--local bundleName = CS.FormatBundleNameByPath(spinePath)
	--if not LResDownload:CheckRes(bundleName) then
	--	defaultSpineName = "Default1"
	--	defaultSpinePath = "Spine/Default1"
	--
	--	self._spineName = defaultSpineName
	--	self._isDefaultShadow = true
	--end

	self._poolItemType = LPoolItemConst.TYPE_SPINE
	if spineType == 1 then
		spineName = spineName.."UI"
		self._poolItemType = LPoolItemConst.TYPE_SPINE_UI
	end

	local loadPath = ""
	if not string.isempty(spineName) then
		loadPath = string.format("%s/%s.prefab", spinePath, spineName)
	end
	self._spineDirPath = spinePath

	self:Create(parentTrans, loadPath, spineName,defaultSpinePath,defaultSpineName)
end

function LDisplaySpine:CreateImpl(parentTrans,spineName,spineType)
	self:CreateSpine(parentTrans,spineName,spineType)
	return true
end

