---初始化spine
function LDisplaySpine:InternalInitSpine()
	self._spineTrans = self:GetDisplayTrans()

	local skeletonAnimation = self._spineTrans:GetComponent(typeOfSkeletonAnimation)
	if skeletonAnimation ~= nil then
		self._initAni = skeletonAnimation.AnimationName
	end
	if self._spineType == LDisplaySpine.TYPE_UI then
		skeletonAnimation =  self._spineTrans:GetComponent(typeOfSkeletonGraphic)
		if(skeletonAnimation and not skeletonAnimation.IsValid) then
			skeletonAnimation:Initialize(false)
		end
		if skeletonAnimation ~= nil then
			self._initAni = skeletonAnimation.startingAnimation
		end
	end

	if not skeletonAnimation then
		LogWarn("cannot find skeletonAnimation : " ..tostring(self._spineName))
		return
	end

	--animationState 在初始化的时候才会创建
	--skeletonAnimation 没有初始化在调用函数 Skeleton 的时候会初始化
	--所以先获取Skeleton
	local skeleton = skeletonAnimation.Skeleton
	local animationState = skeletonAnimation.AnimationState
	
	self._skeletonAnimation = skeletonAnimation
	if not skeleton or not animationState then
		return 
	end

	local skeletonData = skeleton.Data

	self._animationState = animationState
	self._skeleton = skeleton
	self._skeletonData = skeletonData

	self._renderer = self._spineTrans:GetComponent(typeOfMeshRenderer)
	local layerName = self._rendererLayerName
	self._rendererLayerName = ""
	self:SetRenderLayer(layerName)
	local renderOrder = self._rendererOrder
	self._rendererOrder = 0
	self:SetRenderOrder(renderOrder)

	self:UpdateFlip()

	self:UpdateScale()

	if self._bReleaseFreeze then
		self:Freeze(false)
	end

	--为了马上刷新上面的各种设置 调用一次update 强制更新
	skeletonAnimation:Update(0)
	--end 为了马上刷新上面的各种设置 调用一次update 强制更新

	self:RegisterAnimationComplete()

	self:ResumeAnimation()

	self:UpdateSkin()

	if self._isAniSensitive then
		self:CheckDefaultAniSensitive()
	end

	--- 设置胶带
	local wndCls = self._wndCls
	if wndCls and wndCls:IsWndValid() then
		if wndCls and self._spineName and gModelHeroExtra then
			if gModelHeroExtra:CheckNeedShowCloudBySpineName(self._spineName,self,wndCls) then
				return false
			end
		end
	end
	return true
end

--裸露屏蔽检测
function LDisplaySpine:CheckDefaultAniSensitive()
	if string.isempty(self._initAni) then return end
	local ref = GameTable.FilterActionRef[self._initAni]
	if ref then
		self:PlayAnimationSolid(self._initAni, true)
	end
end

--裸露屏蔽动作替换
function LDisplaySpine:GetSensitiveReplaceAct(ani)
	local ref = GameTable.FilterActionRef[ani]
	if ref then
		return ref.replaceAct
	end
	return ani
end

function LDisplaySpine:PlayAnimationSolid(animation,isLoop,ignoreTimeScale)
	if isLoop == nil then
		isLoop = true
	end

	if not self._skeletonAnimation then
		return
	end
	ignoreTimeScale = ignoreTimeScale or false
	self:ClearAnimation(0)
	self:PlayAnimation(0,animation,isLoop,ignoreTimeScale,0)
	self._skeletonAnimation:Update(0)
end

function LDisplaySpine:ForceUpdateAnimation()
	if self._skeletonAnimation then
		self._skeletonAnimation:Update(0)
	end
end

