---动画播放完成
function LDisplaySpine:InternalAnimationCompleteEvent(transEntry)
	local nowTrackEntry = self._curTrackEntry
	if not nowTrackEntry or not nowTrackEntry.Animation then
		return
	end
	local nowName = nowTrackEntry.Animation.Name
	if nowName == transEntry.Animation.Name then
		self:OnAniamationComplete(nowName)
	end
end

function LDisplaySpine:GetCurTrackEntryName()
	local nowTrackEntry = self._curTrackEntry
	if nowTrackEntry ~= nil and nowTrackEntry.Animation ~= nil then
		local nowName = nowTrackEntry.Animation.Name
		return nowName
	end
end

