-- 获取bone  boneName: xxx/xxxx/xxxx
function LDisplaySpine:FindBoneNode(bone, boneName)
	if not self._skeleton then
		return nil
	end
	
	local symbolPos = string.find(boneName, "/")
	if symbolPos then
		local len = string.len(boneName)
		local name1 = string.sub(boneName, 0, symbolPos-1)
		local name2 = string.sub(boneName, symbolPos+1)
		local subBone = nil
		if bone then
			subBone = bone.Skeleton:FindBone(name1)
		else
			subBone = self._skeleton:FindBone(name1)
		end
		if subBone then
			return self:FindBoneNode(subBone, name2)
		end
	end
	
	if bone then
		return bone.Skeleton:FindBone(boneName)
	else
		return self._skeleton:FindBone(boneName)
	end
end
function LDisplaySpine:GetBone(boneName)
	if not self._skeleton then
		return nil
	end
	self._boneMap = self._boneMap or {}
	local bone = self._boneMap[boneName]
	
	if not bone then
		bone = self:FindBoneNode(nil, boneName)
		self._boneMap[boneName] = bone
	end

	return bone
end
--获取bone位置 boneName: xxx/xxxx/xxxx
function LDisplaySpine:GetBonePos(boneName)
	local bone = self:GetBone(boneName)
	if not bone then
		return self:GetPos()
	end
	local trans = self:GetSpineTrans()
	if not trans then
		return Vector3.zero
	end
	
	local pos = trans:TransformPoint(Vector3.New(bone.WorldX, bone.WorldY, 0))
	return pos
end
--获取spine插槽缩放值
function LDisplaySpine:GetBoneScale(boneName)
	local bone = self:GetBone(boneName)
	if not bone then
		return self:GetPos()
	end
	local trans = self:GetSpineTrans()
	if not trans then
		return Vector3.New(1,1,1)
	end

	local pos = Vector3.New(bone.WorldScaleX, bone.WorldScaleY, 0)
	return pos
end

---@return Vector3 UI坐标系的世界坐标
function LDisplaySpine:GetBoneUIPos(boneName, sceneCam, uiCam)
	local bone = self:GetBone(boneName)
	if not bone then
		return self:GetPos()
	end
	local trans = self:GetSpineTrans()
	if not trans then
		return Vector3.zero
	end

	sceneCam = sceneCam or gLGameScene:GetCurrentSceneCamera()
	uiCam = uiCam or LGameUI.GetUICamera()

	--场景0点在ui的位置
	local poszero = Vector3(0,0,0)
	local zerotoscreen = sceneCam:WorldToScreenPoint(poszero)
	local zerotoui = uiCam:ScreenToWorldPoint(zerotoscreen)
	zerotoui.z = 0

	local bone = self:GetBone(boneName)
	local pos = Vector3.New(bone.WorldX, bone.WorldY, 0)
	--bone体系坐标相对场景0点在ui上的位置
	local screenPos = sceneCam:WorldToScreenPoint(pos)
	local uiPos = uiCam:ScreenToWorldPoint(screenPos)
	local finalPos = uiPos + trans.position - zerotoui --UI上最终的位置
	finalPos.z = 0

	return finalPos
end

