---z准备完成
function LDisplaySpine:OnDpReady()
	LDisplayBase.OnDpReady(self)

	self._spineName = self._orgSpineName

	if not self:IsDpValid() then return end

	local interceptSpine = false
	-- 需要加云朵的时候，等云朵加完再显示出来
	if self:InternalInitSpine() then
		self:UpdateVisible()
	else
		interceptSpine = true
		CS.ShowObject(self:GetDisplayTrans(), false)
	end
	self:SetInterceptSpine(interceptSpine)

	self:UpdateAlpha()
end

function LDisplaySpine:OnDestroy()
	if self:IsUsePool() and self._bReleaseFreeze then
		self:Freeze(true)
	end
	self:UnRegisterAnimationComplete()

	if self._textureResRequester then
		self._textureResRequester:Dispose()
		self._textureResRequester = nil
	end

	if self._spineMaterialAsset then
		self._spineMaterialAsset:Dispose()
		self._spineMaterialAsset = nil
	end
	
	LDisplayBase.OnDestroy(self)
end


---动画播放完成
function LDisplaySpine:OnAniamationComplete(animateName)
	if self._curPlayAni == animateName then
		animateName = self._curAnimationName
	end
	--printInfoN(animateName.." play end")
	local func = self._animationCompleteFunc
	if func ~= nil then
		func(animateName)
	end
end
function LDisplaySpine:SetUseLookValid(bUseLook, x1, x2, y1, y2)
	if self._spineType ~= LDisplaySpine.TYPE_MODEL then return end
	self._bUseLookValid = true
	if LNotchUtil then
		local minx, maxx = LNotchUtil.GetViewHorizontalLimit()
		if not x1 then
			x1 = minx - 0.1
		end
		if not x2 then
			x2 = maxx + 0.1
		end
	end
	x1 = x1 or -0.1
	x2 = x2 or 1.1
	y1 = y1 or -0.1
	y2 = y2 or 1.1
	local animation = self._skeletonAnimation
	if animation then
		animation:SetUseLookValid(bUseLook, x1, x2, y1, y2)
	end
end
