---播放动画
---@param mixTime number|nil
---@param loop boolean|nil
---@param ignoreTimeScale boolean|nil
---@param ani string
---@param trackIndex number @comment default = 0
function LDisplaySpine:PlayAnimation(trackIndex, ani, loop, ignoreTimeScale,mixTime)
	if not self:IsDpValid() then return false end
	if not self._skeletonData then return false end

	local oldAni = ani
	if self._isAniSensitive then
		ani = self:GetSensitiveReplaceAct(ani)
	end

	mixTime = mixTime or -1
	ignoreTimeScale = ignoreTimeScale or false
	loop = loop or false and true

	local animationState = self._animationState
	local animation = self._skeletonAnimation
	if (not self._skeletonData:FindAnimation(ani)) then
		if self._isDefaultShadow then
			ani = "skill1"
		else
			animationState:ClearTrack(trackIndex)
			return false
		end 
	end
	
	if mixTime == 0 then
		--animationState:ClearTrack(trackIndex)
		--animationState:SetEmptyAnimations(0)
	end
	
	self._curAnimationName = oldAni
	self._curPlayAni = ani

	self._bIgnoreTimeScale = ignoreTimeScale
	animation.UnscaledTime = ignoreTimeScale and true or false

	self._curTrackEntry = animationState:SetAnimation(trackIndex, ani, loop)

	if (mixTime >= 0) then
		self._curTrackEntry.MixDuration = mixTime
		--self._curTrackEntry.MixTime = mixTime
	end
	return true
end

function LDisplaySpine:IsHaveAnimation(ani)
	if (not self._skeletonData:FindAnimation(ani)) then
		return false
	end
	return true
end

---增加动画轨道
---tranckIndex 一般都大于0
function LDisplaySpine:AddAnimation(trackIndex,ani,loop)
	if not self:IsDpValid() then return end
	if (not self._skeletonData:FindAnimation(ani)) then
		return
	end
	self._animationState:AddAnimation(trackIndex, ani, loop, 0)
end

function LDisplaySpine:ClearAnimationAll()
	if not self:IsDpValid() then return end
	if self._animationState then self._animationState:SetEmptyAnimations(0) end
end

function LDisplaySpine:ClearAnimation(tranckIndex)
	if not self:IsDpValid() then return end
	if self._animationState then self._animationState:SetEmptyAnimation(tranckIndex,0) end
end

function LDisplaySpine:SetScale(scale)
	self._scale = scale
	self:UpdateScale()
end

function LDisplaySpine:UpdateScale()
	if not self:IsDpValid() then return end
	local scale = self._scale
	self:GetDisplayTrans().localScale = Vector3(scale,scale,scale)
end

function LDisplaySpine:UpdateFlip()
	if not self:IsDpValid() then return end
	local bFilp = self._isFlipX
	if self._skeleton then
		self._skeleton.ScaleX = (bFilp and -1 or 1)
	end
end

--恢复设置位置，对于那些多个元素合在一起的spine，调用播放动作，发现位置不对的时候可以先调用此函数
function LDisplaySpine:SetToSetupPose()
	if not self:IsDpValid() then return end
	self._skeleton:SetToSetupPose()
end

function LDisplaySpine:IsFlipX()
	return self._isFlipX
end

function LDisplaySpine:SetFlipX(bFilp)
	self._isFlipX = bFilp
	self:UpdateFlip()
end

function LDisplaySpine:GetAlpha()
	return self._alpha
end

function LDisplaySpine:SetAlpha(alpha)
	self._alpha = alpha
	if not self:IsDpValid() then return end
	self:UpdateAlpha()
end

function LDisplaySpine:UpdateAlpha()
	if not self:IsDpValid() then return end
	if self._alpha then
		if self._spineType == LDisplaySpine.TYPE_UI then
			local color = self._skeletonAnimation.color
			color.a = self._alpha
			self._skeletonAnimation.color = color
		else
			if self._skeleton then self._skeleton.A = self._alpha end
		end
	end
end

function LDisplaySpine:PauseAnimation()
	self._pause = true
	if not self:IsDpValid() then return end
	local animation = self._skeletonAnimation
	--animation.UnscaledTime = false
	animation.timeScale = 0
end

function LDisplaySpine:ResumeAnimation()
	self._pause = false
	if not self:IsDpValid() then return end
	local animation = self._skeletonAnimation
	--animation.UnscaledTime = self._bIgnoreTimeScale or false and true
	animation.timeScale = self._animationTimeScale or 1
end

function LDisplaySpine:SetAnimationTimeScale(timeScale)
	if self._animationTimeScale == timeScale then return end
	self._animationTimeScale = timeScale
	if not self._pause then
		if self._skeletonAnimation then
			self._skeletonAnimation.timeScale = timeScale or 1
		end
	end
end

function LDisplaySpine:SetRenderOrder(order)
	if self._rendererOrder == order then
		return
	end

	self._rendererOrder = order or 0

	if not self:IsDpValid() then
		return
	end
	if self._renderer then
		self._renderer.sortingOrder = self._rendererOrder
	end
end

function LDisplaySpine:GetRenderOrder()
	return self._rendererOrder
end

--层级
function LDisplaySpine:SetRenderLayer(layerName)
	if string.isempty(layerName) then
		return
	end
	if self._rendererLayerName == layerName then
		return
	end

	self._rendererLayerName = layerName

	if not self:IsDpValid() then
		return
	end

	if (self._renderer) then
		self._renderer.sortingLayerName = layerName
	end
end

function LDisplaySpine:GetRenderLayer()
	if not self:IsDpValid() then
		return self._rendererLayerName
	end

	if (self._renderer) then
		return self._renderer.sortingLayerName
	end

	return self._rendererLayerName
end

function LDisplaySpine:GetCurAnimationName()
	return self._curAnimationName
end

function LDisplaySpine:GetSpineTrans()
	return self._spineTrans
end

function LDisplaySpine:GetPos()
	local trans = self:GetSpineTrans()
	if trans then
		return trans.position
	else
		return Vector3.zero
	end
end

function LDisplaySpine:GetSpineName()
	return self._spineName
end

function LDisplaySpine:Freeze(bFreeze)
	if self._skeletonAnimation then
		self._skeletonAnimation.freeze = bFreeze
	end
end

function LDisplaySpine:EnableReleaseFreeze(bEnable)
	self._bReleaseFreeze = bEnable
end

function LDisplaySpine:MatchRectTransform()
	if self._spineType == LDisplaySpine.TYPE_UI then
		if self._skeletonAnimation then
			self._skeletonAnimation:MatchRectTransformWithBounds()
		end
	end
end

function LDisplaySpine:SetColor(color,noAlpha)
	self._color = color
	if not self:IsDpValid() then return end
	if self._spineType == LDisplaySpine.TYPE_UI then
		self._skeletonAnimation.color=color
	elseif self._skeleton then
		self._skeleton.R = color.r
		self._skeleton.G = color.g
		self._skeleton.B = color.b
		if not noAlpha then
			self._skeleton.A = color.a
		end
	end
end

function LDisplaySpine:SetRaycastTarget(isActive)
	if not self:IsDpValid() then return end
	if self._spineType == LDisplaySpine.TYPE_UI then
		self._skeletonAnimation.raycastTarget=isActive
	end
end

function LDisplaySpine:SetVisible(bVisible)
	bVisible = bVisible and true or false
	if self._bVisible == bVisible then return end
	self._bVisible = bVisible

	self:UpdateVisible()
end

function LDisplaySpine:SetInterceptSpine(bInterceptSpine)
	self._interceptSpine = bInterceptSpine
end

function LDisplaySpine:UpdateVisible()
	if not self:IsDpValid() then return end
	if self._interceptSpine then return end
	CS.ShowObject(self:GetDisplayTrans(), self._bVisible)
end

function LDisplaySpine:ResetSpine()
	if not self:IsDpValid() then return end
	self._animationState:ClearTracks()
	self._skeleton:SetToSetupPose()
	
	self:SetAlpha(1)
end

function LDisplaySpine:SetSlotAlpha(boneName, alpha)
	if not self._skeleton then
		return
	end 
	
	local spineSlot = self._skeleton:FindSlot(boneName)
	if spineSlot then
		spineSlot.A = alpha
	end
	
end

function LDisplaySpine:SetIgnoreTimeScale(ignoreTimeScale)
	if self._bIgnoreTimeScale == ignoreTimeScale then
		return
	end
	self._bIgnoreTimeScale = ignoreTimeScale or false

	if self._skeletonAnimation then
		self._skeletonAnimation.UnscaledTime = self._bIgnoreTimeScale
	end
end

function LDisplaySpine:SetUITexture(name)
	if self._spineType ~= LDisplaySpine.TYPE_UI then
		return 
	end

	if string.isempty(name) then return end
	if string.isempty(self._assetPath) then return end

	if self._textureResRequester then
		self._textureResRequester:Dispose()
		self._textureResRequester = nil
	end
	name = gLGameLanguage:GetResName(name)

	self._textureResRequester = LxResUtil.GetAssetRequester(self._spineDirPath .. "/" ..name..".png" , typeofTexture,function(texture)
		if not texture then
			return
		end
		self._textureObj = texture
		if self._skeletonAnimation then
			self._skeletonAnimation.OverrideTexture = texture
		end
	end)
	self._textureResRequester:StartRequester()
end

function LDisplaySpine:SetUITextureEx(assetPath,name,endFunc)
	if self._spineType ~= LDisplaySpine.TYPE_UI then
		return
	end
	local image = gLGameLanguage:GetResName(name)
	if string.isempty(image) then return end
	if string.isempty(assetPath) then return end
	-- Async_FindTexture使用异步true
	image = image..".png"

	if self._textureResRequester then
		self._textureResRequester:Dispose()
		self._textureResRequester = nil
	end
	self._textureResRequester = LxResUtil.GetAssetRequester(assetPath.."/"..image, typeofTexture,function(texture)
		if not texture then
			return
		end
		self._textureObj = texture
		if self._skeletonAnimation then
			self._skeletonAnimation.OverrideTexture = texture
		end

		if endFunc then
			endFunc()
		end
	end)
	self._textureResRequester:StartRequester()
end

function LDisplaySpine:SetUISpineGray(bGray)
	if self._bUIGray == bGray then return end
	self._bUIGray = bGray
	if self._spineType ~= LDisplaySpine.TYPE_UI then return end
	if not self._skeletonAnimation then return end
	if bGray then
		self._skeletonAnimation.material = LxResUtil.GetSpineGrayMaterial()
	else
		self._skeletonAnimation.material = LxResUtil.GetSpineDefaultMaterial()
	end
end

--------------------------------------------------------------------------------
-- showTime：冰冻时间
-- aniTime: 进入冰冻的时间
-- reverseTime: 解冻时间
function LDisplaySpine:SetSpineMat(matKey, showTime, aniTime, reverseTime,endFunc)
	if CS.IsNullObject(self._spineTrans) or CS.IsNullObject(self._renderer) then
		return
	end
	showTime = showTime or -1
	aniTime = aniTime or -1
	reverseTime = reverseTime or -1

	if self._ctSpineObj == nil then
		self._ctSpineObj = self._spineTrans:GetComponent(typeofYXSpineObject)
		if self._ctSpineObj == nil then
			self._ctSpineObj = self._spineTrans.gameObject:AddComponent(typeofYXSpineObject)
		end
	end
	
	local mathName = string.format("%s_Material_%s", self._spineName, matKey) 
	local curSpineMatName = string.lower(self._curSpineMatName)
	local assetName = string.lower(mathName)
	if curSpineMatName == assetName then
		return
	end
	self._curSpineMatName = mathName

	if self._spineMaterialAsset then
		self._spineMaterialAsset:Dispose()
		self._spineMaterialAsset = nil
	end

	self._spineMaterialAsset = require("LApp.component.res.LxMaterialAsset"):New(self._spineDirPath .."/".. mathName..".mat")
	self._spineMaterialAsset:AddRequestCb(function(asset, assetPath)
		local curMatName = string.lower(self._curSpineMatName)
		if CS.IsValidObject(asset) then
			local newMatName = string.lower(asset.name)
			if curMatName == newMatName then
				self._curSpineMat = asset
				self._renderer.sharedMaterial = asset
				self._ctSpineObj:SetSpineMaterial(asset, aniTime)
			end
		end
		if endFunc then
			endFunc()
		end
	end)
	self._spineMaterialAsset:LoadMaterial()

	if showTime > 0 then
		LxTimer.DelayTimeCall(function()
			self:SetSpineDefaultMat(reverseTime)
		end, showTime)
	end
	
end
-- aniTime: 解冻时间
function LDisplaySpine:SetSpineDefaultMat(aniTime)
	if CS.IsNullObject(self._spineTrans) or CS.IsNullObject(self._renderer) then
		return
	end
	if self._ctSpineObj == nil then
		return
	end
	local matName = string.lower( string.format("%s_Material", self._spineName) )
	if self._curSpineMatName == matName then
		return
	end
	--local sharedMaterial = self._renderer.sharedMaterial
	--if CS.IsValidObject(sharedMaterial) then
	--	local curName = string.lower(sharedMaterial.name)
	--	if mathName == curName then
	--		return
	--	end
	--end
	self._curSpineMatName = matName
	aniTime = aniTime or -1
	self._ctSpineObj:SetDefaultMaterial(aniTime)
	self._curSpineMat = nil
end

function LDisplaySpine:GetTopNodeInfo()
	local trans = self:GetDisplayTrans()
	if not CS.IsValidObject(trans) then
		return
	end
	local topNode = self._topNodeTrans
	if not topNode then
		topNode = CS.FindTrans(trans,"TopNode")
		self._topNodeTrans = topNode
		self._defaultTopNodePos = topNode.localPosition
	end

	return self._topNodeTrans,self._defaultTopNodePos
end

function LDisplaySpine:SetUIMaterial(matKey)
	if self._spineType ~= LDisplaySpine.TYPE_UI then
		return
	end

	local mathName = string.format("%s_Material_Graphic_%s", self._spineName, matKey)
	local curSpineMatName = string.lower(self._curSpineMatName)
	local assetName = string.lower(mathName)
	if curSpineMatName == assetName then
		return
	end
	self._curSpineMatName = mathName
	if self._spineMaterialAsset then
		self._spineMaterialAsset:Dispose()
		self._spineMaterialAsset = nil
	end
	self._spineMaterialAsset = require("LApp.component.res.LxMaterialAsset"):New(self._spineDirPath .."/".. mathName..".mat")
	self._spineMaterialAsset:AddRequestCb(function(asset, assetPath)
		local curMatName = string.lower(self._curSpineMatName)
		if CS.IsValidObject(asset) then
			local newMatName = string.lower(asset.name)
			if curMatName == newMatName then
				self._curSpineMat = asset
				self._skeletonAnimation.material = asset
			end
		end
	end)
	self._spineMaterialAsset:LoadMaterial()
end

function LDisplaySpine:SetSkin(skinName)
	if(self._skeleton)then
		local skin = self._skeletonData:FindSkin(skinName)
		if(skin)then
			self._skeleton:SetSkin(skinName)
		end
	end
end

function LDisplaySpine:SetChangeStatus(changeStatus)
	local skinName = changeStatus ~= 1 and "a" or "b"
	self._skinName = skinName
	self:SetSkin(skinName)
end

function LDisplaySpine:UpdateSkin()
	if self._skinName then
		self:SetSkin(self._skinName)
	end
end

function LDisplaySpine:GetSkeletonAnimation()
	return self._skeletonAnimation
end

-----------------------------------------------------------------
return LDisplaySpine